<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <title>Kanban Board</title>
  <style>
    body { font-family: sans-serif; }
    #container { display: flex; }
    #col-todo, #col-doing, #col-done { width: 25%; border: 1px solid #ccc; padding: 10px; min-height: 300px; overflow-y: auto; }
    .count { font-weight: bold; margin-bottom: 5px; }
    .card { background-color: #f9f9f9; border: 1px solid #ddd; padding: 10px; cursor: move; }
    .card-del { float: right; color: red; font-weight: bold; padding: 5px; }
  </style>
</head>
<body>

  <div id="container">
    <div id="col-todo" draggable="true">
      <span class="count">0</span>
    </div>
    <div id="col-doing" draggable="true">
      <span class="count">0</span>
    </div>
    <div id="col-done" draggable="true">
      <span class="count">0</span>
    </div>

    <input type="text" id="new-card" placeholder="New card title">
    <button id="add-card">Add Card</button>
  </div>

  <script>
    const boardData = JSON.parse(localStorage.getItem('board') || '[]');
    const todoCol = document.getElementById('col-todo');
    const doingCol = document.getElementById('col-doing');
    const doneCol = document.getElementById('col-done');
    const newCardInput = document.getElementById('new-card');
    const addCardButton = document.getElementById('add-card');

    function updateCounts() {
      document.querySelectorAll('#col-todo .count, #col-doing .count, #col-done .count').forEach(count => {
        count.textContent = boardData.filter(card => card.column === count.parentNode.id).length;
      });
    }

    function renderCards() {
      boardData.forEach(card => {
        const cardElement = document.createElement('div');
        cardElement.classList.add('card');
        cardElement.textContent = card.title;
        cardElement.setAttribute('draggable', 'true');

        cardElement.addEventListener('dragstart', (e) => {
          e.dataTransfer.setData('text/plain', JSON.stringify(card));
        });

        cardElement.addEventListener('dragover', (e) => {
          e.preventDefault();
        });

        cardElement.addEventListener('drop', (e) => {
          const cardData = e.dataTransfer.getData('text/plain');
          const droppedCard = JSON.parse(cardData);
          const columnId = e.target.id;

          boardData = boardData.map(card =>
            card.title === droppedCard.title ? { ...card, column: columnId } : card
          );
          localStorage.setItem('board', JSON.stringify(boardData));
          updateCounts();
        });

        cardElement.addEventListener('dragend', (e) => {
          // Optional:  Perform cleanup here if needed.
        });


        const deleteButton = document.createElement('button');
        deleteButton.classList.add('card-del');
        deleteButton.textContent = 'Delete';
        deleteButton.addEventListener('click', () => {
          boardData = boardData.filter(card => card.title !== droppedCard.title);
          localStorage.setItem('board', JSON.stringify(boardData));
          updateCounts();
          renderCards(); // Re-render to remove the deleted card
        });

        cardElement.appendChild(deleteButton);
        e.target.parentNode.appendChild(cardElement);
      });
    }


    addCardButton.addEventListener('click', () => {
      const cardTitle = newCardInput.value.trim();
      if (cardTitle) {
        boardData.push({ title: cardTitle, column: 'col-todo' });
        localStorage.setItem('board', JSON.stringify(boardData));
        renderCards();
        updateCounts();
        newCardInput.value = '';
      }
    });

    // Initial render and persistence setup
    window.onload = () => {
      if (boardData.length > 0) {
        renderCards();
        updateCounts();
      }
    };
  </script>

</body>
</html>
